"import re\nimport uuid\nimport os\nfrom src.config import Config\n\ndef sanitize_text(text: str) -> str:\n    \"\"\"\n    Membersihkan tag emosi dari teks agar tidak dibaca oleh TTS.\n    \"\"\"\n    text = text.replace('[BREATH]', '... ').replace('[SIGH]', '(sigh)... ')\n    clean = re.sub(r'\[HAPPY\]|\[SAD\]|\[ANGRY\]|\[WHISPER\]', '', text)\n    return clean.strip()\n\ndef get_emotion_settings(text: str) -> dict:\n    \"\"\"\n    Menentukan parameter stabilitas dan kemiripan suara berdasarkan tag emosi.\n    \"\"\"\n    settings = {\"stability\": 0.5, \"similarity_boost\": 0.75, \"style\": 0.0}\n    if \"[HAPPY]\" in text: \n        settings = {\"stability\": 0.3, \"similarity_boost\": 0.8, \"style\": 0.8}\n    elif \"[SAD]\" in text: \n        settings = {\"stability\": 0.2, \"similarity_boost\": 0.8, \"style\": 0.4}\n    elif \"[ANGRY]\" in text: \n        settings = {\"stability\": 0.3, \"similarity_boost\": 0.9, \"style\": 1.0}\n    elif \"[WHISPER]\" in text: \n        settings = {\"stability\": 0.6, \"similarity_boost\": 0.7, \"style\": 0.1}\n    return settings\n\ndef generate_unique_voice_path() -> str:\n    \"\"\"\n    Menghasilkan path file unik di dalam folder TEMP_DIR untuk menghindari race condition.\n    \"\"\"\n    unique_id = uuid.uuid4().hex\n    filename = f\"voice_{unique_id}.mp3\"\n    return os.path.join(Config.TEMP_DIR, filename)\n"